Simulation_Ability={}function Simulation_Ability:New(a,b)local c={}setmetatable(c,self)self.__index=self;c:Build(a,b)return c end;function Simulation_Ability:Build(a,b)self.type=a;self.nameID=Simulation_Controller.ABILITY_NAME_ID+self.type;self.nameLongID=Simulation_Controller.ABILITY_NAME_LONG_ID+self.type;self.descID=Simulation_Controller.ABILITY_DESC_ID+self.type;self.descInfluenceID=Simulation_Controller.ABILITY_INFLUENCE_ID+self.type;self.strID=Simulation_Controller.ABILITY_STR[self.type]self.pathImg=Simulation_Controller.ICON_PATH..self.type;self:SetCount(b or 0)end;function Simulation_Ability:SetCount(b)self.count=tonumber(b)or 0;self.countStr=math.floor(math.abs(self.count/100))local d=(self.count>0 and"+"or"-")..self.countStr;local e=self.count>0 and Simulation_Controller.COLOR_ADD or Simulation_Controller.COLOR_SUB;self.countStrWithColor='<color=#'..e..'>'..d..'</color>'end;function Simulation_Ability.GetCountStr(b)local f=math.floor(math.abs(b/100))local d=(b>0 and"+"or"-")..f;local e=b>0 and Simulation_Controller.COLOR_ADD or Simulation_Controller.COLOR_SUB;local g={count=b,countStr=f,countStrWithColor='<color=#'..e..'>'..d..'</color>'}return g end;return Simulation_Ability